"use client";

import * as React from "react";
import {
  Building2,
  GalleryVerticalEnd,
  Kanban,
  TrendingUp,
  Activity,
  Users,
  Mail,
  AlertTriangle,
  HelpCircle,
  UserCheck,
  Briefcase,
} from "lucide-react";

import { NavMain } from "./nav-main";
import { Billing } from "./billing";
import {
  Sidebar,
  SidebarContent,
  SidebarFooter,
  SidebarHeader,
  SidebarMenuButton,
  SidebarRail,
} from "./ui/sidebar";
import { NavReporting } from "./nav-reporting";
import { NavSecondary } from "./nav-secondary";
import { NavTeams } from "./nav-teams";
import { NavPipelines } from "./nav-pipelines";

export const data = {
  user: {
    name: "John Doe",
    email: "john@example.com",
    avatar: "/avatars/john.jpg",
  },
  company: {
    name: "Sales CRM",
    logo: GalleryVerticalEnd,
    plan: "Company Pipeline",
  },
  navMain: [
    {
      title: "Companies",
      url: "#",
      icon: Building2,
      isActive: true,
    },
    {
      title: "Deals Board",
      url: "#",
      icon: Kanban,
    },
    {
      title: "Forecast",
      url: "#",
      icon: TrendingUp,
      isDisabled: true,
    },
    {
      title: "Activities",
      url: "#",
      icon: Activity,
      isDisabled: true,
    },
    {
      title: "Contacts",
      url: "#",
      icon: Users,
      isDisabled: true,
    },
    {
      title: "Email Sequences",
      url: "#",
      icon: Mail,
      isDisabled: true,
    },
  ],
  navSecondary: [
    {
      title: "Invite teammates",
      url: "#",
      icon: Users,
      isDisabled: true,
    },
    {
      title: "Help",
      url: "#",
      icon: HelpCircle,
      isDisabled: true,
    },
  ],
  teams_section: [
    {
      name: "Strategic AEs",
      url: "#",
      icon: UserCheck,
      isDisabled: true,
    },
    {
      name: "Mid Market",
      url: "#",
      icon: Briefcase,
      isDisabled: true,
    },
    {
      name: "SDR Team",
      url: "#",
      icon: Users,
      isDisabled: true,
    },
  ],
  reporting: [
    {
      name: "Q1 Forecast",
      url: "#",
      icon: TrendingUp,
      isDisabled: true,
    },
    {
      name: "Slipping Deals",
      url: "#",
      icon: AlertTriangle,
      isDisabled: true,
    },
  ],
  pipelines: [
    {
      name: "North America",
      url: "#",
      color: "text-yellow-500",
      isDisabled: true,
    },
    {
      name: "EMEA Enterprise",
      url: "#",
      color: "text-pink-500",
      isDisabled: true,
    },
    {
      name: "APAC Expansion",
      url: "#",
      color: "text-blue-500",
      isDisabled: true,
    },
  ],
};

export function AppSidebar({ onNavigate, currentView, ...props }: React.ComponentProps<typeof Sidebar> & { onNavigate?: (view: string) => void; currentView?: string }) {
  return (
    <Sidebar collapsible="icon" {...props}>
      <SidebarHeader className="border-b border-neutral-200 dark:border-neutral-800 data-[state=open]:py-1">
        <SidebarMenuButton
          size="lg"
          className="hover:bg-transparent data-[state=open]:text-sidebar-accent-foreground active:bg-transparent"
        >
          <div className="bg-neutral-100 dark:bg-neutral-700 text-neutral-900 dark:text-sidebar-primary-foreground flex aspect-square size-8 items-center justify-center rounded-md border border-neutral-200 dark:border-neutral-600">
            <data.company.logo className="size-4" />
          </div>
          <div className="grid flex-1 text-left text-sm leading-tight">
            <span className="truncate font-medium text-sm">
              {data.company.name}
            </span>
            <span className="truncate text-xs text-neutral-500 dark:text-neutral-400 font-medium">
              {data.company.plan}
            </span>
          </div>
        </SidebarMenuButton>
      </SidebarHeader>
      <SidebarContent>
        <NavMain items={data.navMain} onNavigate={onNavigate} currentView={currentView} />
        <NavTeams teams={data.teams_section} />
        <NavReporting reports={data.reporting} />
        <NavPipelines pipelines={data.pipelines} />
        <NavSecondary items={data.navSecondary} className="mt-auto" />
      </SidebarContent>
      <SidebarFooter className="border-t border-neutral-200 dark:border-neutral-800 py-1 group-data-[collapsible=icon]:py-1.5">
        <Billing />
      </SidebarFooter>
      <SidebarRail />
    </Sidebar>
  );
}

'use client';
import { useMemo } from 'react';

import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from './ui/table';
import { Badge } from './ui/badge';
import { Checkbox } from './ui/checkbox';
import { Avatar, AvatarFallback, AvatarImage } from './ui/avatar';
import { Separator } from './ui/separator';
import { Calendar, Plus } from 'lucide-react';
import { companiesData, segmentColors } from '../data';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
  DialogClose,
} from './ui/dialog';
import { Input } from './ui/input';
import { Button } from './ui/button';

function WinProbabilityBar({ value }: { value: number }) {
  const filledBars = Math.round((value / 100) * 20);
  const redBars = Math.round(filledBars * 0.33);
  const yellowBars = Math.round(filledBars * 0.33);
  const greenBars = filledBars - redBars - yellowBars;

  return (
    <div className="flex items-center gap-2">
      <div className="flex h-3 w-fit items-center gap-0.5">
        {Array.from({ length: 20 }).map((_, i) => {
          let barColor = 'bg-neutral-200 dark:bg-neutral-700';
          if (i < redBars) {
            barColor = 'bg-red-500';
          } else if (i < redBars + yellowBars) {
            barColor = 'bg-yellow-500';
          } else if (i < redBars + yellowBars + greenBars) {
            barColor = 'bg-green-500';
          }
          return <div key={i} className={`h-full w-0.5 ${barColor}`} />;
        })}
      </div>
      <span className="text-sm font-bold whitespace-nowrap text-neutral-600 dark:text-neutral-300">
        {value}%
      </span>
    </div>
  );
}

function ActivityTrend() {
  const heights = useMemo(
    // eslint-disable-next-line react-hooks/purity
    () => Array.from({ length: 12 }).map(() => `${Math.random() * 100}%`),
    [],
  );

  return (
    <div className="flex h-3 items-end gap-0.5">
      {heights.map((height, i) => (
        <div
          key={i}
          className="w-1 bg-green-500"
          style={{ height, minHeight: '2px' }}
        />
      ))}
    </div>
  );
}

export function CompaniesTable() {
  const totalCompanies = companiesData.length;

  return (
    <div className="flex flex-col overflow-hidden border-y border-neutral-200 dark:border-neutral-800">
      <div className="overflow-x-auto">
        <Table>
          <TableHeader>
            <TableRow className="border-b border-neutral-200 hover:bg-transparent dark:border-neutral-800">
              <TableHead className="w-12 px-4">
                <Checkbox />
              </TableHead>
              <TableHead className="min-w-[150px] px-4 text-xs text-neutral-500 dark:text-neutral-500">
                Companies
              </TableHead>
              <TableHead className="min-w-[200px] px-4 text-xs text-neutral-500 dark:text-neutral-500">
                Segment & Stage
              </TableHead>
              <TableHead className="min-w-[180px] px-4 text-xs text-neutral-500 dark:text-neutral-500">
                Account Owner
              </TableHead>
              <TableHead className="min-w-[100px] px-4 text-xs text-neutral-500 dark:text-neutral-500">
                Open Deals
              </TableHead>
              <TableHead className="min-w-[140px] px-4 text-xs text-neutral-500 dark:text-neutral-500">
                Pipeline Value
              </TableHead>
              <TableHead className="min-w-[150px] px-4 text-xs text-neutral-500 dark:text-neutral-500">
                Win Probability
              </TableHead>
              <TableHead className="min-w-[120px] px-4 text-xs text-neutral-500 dark:text-neutral-500">
                Activity Trend
              </TableHead>
              <TableHead className="min-w-[180px] px-4 text-xs text-neutral-500 dark:text-neutral-500">
                Last Interaction
              </TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {companiesData.map((company) => (
              <TableRow
                key={company.id}
                className="cursor-pointer border-b border-neutral-200 transition-colors hover:bg-neutral-50 dark:border-neutral-800 dark:hover:bg-neutral-900/50"
              >
                <TableCell className="px-4">
                  <Checkbox />
                </TableCell>
                <TableCell className="px-4 font-medium text-neutral-900 dark:text-white">
                  {company.name}
                </TableCell>
                <TableCell className="flex items-center gap-2 px-4">
                  {company.segments.map((segment) => (
                    <Badge
                      key={segment}
                      className={`${segmentColors[segment]} text-xs font-medium`}
                      variant="secondary"
                    >
                      {segment}
                    </Badge>
                  ))}
                </TableCell>
                <TableCell className="px-4">
                  <div className="flex items-center gap-2">
                    <Avatar className="size-5">
                      <AvatarImage src={company.accountOwner.avatar} />
                      <AvatarFallback>
                        {company.accountOwner.name.charAt(0)}
                      </AvatarFallback>
                    </Avatar>
                    <span className="text-sm text-neutral-700 dark:text-neutral-300">
                      {company.accountOwner.name}
                    </span>
                  </div>
                </TableCell>
                <TableCell className="px-4 text-neutral-700 dark:text-neutral-300">
                  {company.openDeals}
                </TableCell>
                <TableCell className="px-4 text-neutral-700 dark:text-neutral-300">
                  ${company.pipelineValue.toLocaleString('en-US')}
                </TableCell>
                <TableCell className="px-4">
                  <WinProbabilityBar value={company.winProbability} />
                </TableCell>
                <TableCell className="px-4">
                  <ActivityTrend />
                </TableCell>
                <TableCell className="px-4 text-neutral-600 dark:text-neutral-400">
                  <div className="flex items-center gap-2">
                    <Calendar className="size-4 text-neutral-400 dark:text-neutral-500" />
                    <span className="text-sm">
                      {company.lastInteraction.date}
                    </span>
                    <Separator
                      orientation="vertical"
                      className="bg-neutral-200 data-[orientation=vertical]:h-4 dark:bg-neutral-800"
                    />
                    <span className="text-xs text-neutral-400 dark:text-neutral-500">
                      {company.lastInteraction.type}
                    </span>
                  </div>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </div>
      <div className="flex w-full flex-col border-t border-neutral-200 bg-neutral-50 px-4 text-sm text-neutral-600 md:flex-row dark:border-neutral-800 dark:bg-neutral-900/50 dark:text-neutral-500">
        <div className="flex flex-1 items-center gap-2 border-b border-neutral-200 py-2.5 md:border-r md:border-b-0 dark:border-neutral-800">
          <span className="font-semibold text-neutral-900 dark:text-neutral-300">
            {totalCompanies}
          </span>
          <span> Companies in view</span>
        </div>
        <div className="flex flex-1 items-center gap-2 border-b border-neutral-200 py-2.5 md:border-r md:border-b-0 md:pl-3 dark:border-neutral-800">
          <Plus className="size-3.5" />
          <span>Sum of pipeline</span>
        </div>
        <div className="flex flex-1 items-center gap-2 border-b border-neutral-200 py-2.5 md:border-r md:border-b-0 md:pl-3 dark:border-neutral-800">
          <Plus className="size-3.5" />
          <span>Avg win probability</span>
        </div>
        <Dialog>
          <DialogTrigger
            render={
              <div className="group flex flex-1 cursor-pointer items-center justify-start gap-2 py-2.5 transition-colors hover:text-neutral-900 md:pl-3 dark:hover:text-neutral-200" />
            }
          >
            <Plus className="size-3.5" />
            <span>Add Calculation</span>
          </DialogTrigger>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>Add Custom Calculation</DialogTitle>
              <DialogDescription>
                Define a new metric or calculation to display in the footer.
              </DialogDescription>
            </DialogHeader>
            <div className="grid gap-4 py-4">
              <div className="grid gap-2">
                <Input
                  id="calc-name"
                  placeholder="Calculation Name (e.g., Total Revenue)"
                />
              </div>
              <div className="grid gap-2">
                <Input
                  id="calc-formula"
                  placeholder="Formula (e.g., SUM(Pipeline Value))"
                />
              </div>
            </div>
            <DialogFooter>
              <DialogClose
                render={<Button variant="outline" className="rounded-full" />}
              >
                Cancel
              </DialogClose>
              <Button className="rounded-full bg-indigo-600 text-white hover:bg-indigo-700">
                Add Calculation
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>
    </div>
  );
}

import { type Deal } from '../types';

interface DealCardProps {
  deal: Deal;
}

const Sparkline: React.FC<{ data: number[] }> = ({ data }) => {
  const max = Math.max(...data);
  return (
    <div className="flex h-3 items-end gap-[1px]">
      {data.map((v, i) => (
        <div
          key={i}
          className="w-1 rounded-t-[0.5px] bg-teal-500/80"
          style={{ height: `${(v / max) * 100}%` }}
        />
      ))}
    </div>
  );
};

const ProbabilityBar: React.FC<{ value: number }> = ({ value }) => {
  return (
    <div className="flex items-center gap-1.5">
      <div className="flex h-2.5 w-12 gap-[1px]">
        {[...Array(10)].map((_, i) => {
          const isActive = (i + 1) * 10 <= value;
          let color = 'bg-neutral-200 dark:bg-neutral-800';
          if (isActive) {
            if (value > 75) color = 'bg-green-500';
            else if (value > 40) color = 'bg-yellow-500';
            else color = 'bg-red-500';
          }
          return <div key={i} className={`flex-1 rounded-[1px] ${color}`} />;
        })}
      </div>
      <span className="text-[10px] font-bold text-neutral-500 dark:text-neutral-500">
        {value}%
      </span>
    </div>
  );
};

const DealCard: React.FC<DealCardProps> = ({ deal }) => {
  return (
    <div className="group cursor-pointer rounded-xl border border-neutral-200 bg-neutral-50 p-4 transition-colors hover:border-neutral-300 dark:border-neutral-700/90 dark:bg-neutral-800/50 dark:hover:border-neutral-600">
      <div className="mb-1.5 flex items-start justify-between">
        <h4 className="truncate text-sm font-semibold text-neutral-600 transition-colors group-hover:text-indigo-600 dark:text-neutral-400 dark:group-hover:text-indigo-400">
          {deal.company}
        </h4>
      </div>

      <div className="mb-3 text-lg font-bold tracking-tight text-neutral-900 dark:text-white">
        ${deal.value.toLocaleString()}
      </div>

      <div className="mb-3 flex flex-wrap gap-1.5">
        <span
          className={`rounded px-2 py-0.5 text-[10px] font-bold ${
            deal.segment === 'Enterprise'
              ? 'border border-blue-200 bg-blue-100 text-blue-700 dark:border-blue-800 dark:bg-blue-900/30 dark:text-blue-400'
              : deal.segment === 'Mid-Market'
                ? 'border border-teal-200 bg-teal-100 text-teal-700 dark:border-teal-800 dark:bg-teal-900/30 dark:text-teal-400'
                : 'border border-yellow-200 bg-yellow-100 text-yellow-700 dark:border-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-400'
          }`}
        >
          {deal.segment}
        </span>
        {deal.tags.map((tag) => (
          <span
            key={tag}
            className="rounded border border-neutral-300 bg-neutral-200 px-2 py-0.5 text-[10px] font-bold text-neutral-600 dark:border-neutral-700 dark:bg-neutral-800 dark:text-neutral-400"
          >
            {tag}
          </span>
        ))}
      </div>

      <div className="space-y-2.5 border-t border-neutral-200 pt-3 dark:border-neutral-800">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <img
              src={deal.owner.avatar}
              className="h-5 w-5 rounded-full"
              alt={deal.owner.name}
            />
            <span className="text-[11px] font-medium text-neutral-600 dark:text-neutral-500">
              {deal.owner.name}
            </span>
          </div>
          <Sparkline data={deal.activityHistory} />
        </div>

        <div className="flex items-center justify-between">
          <ProbabilityBar value={deal.winProbability} />
          <div className="flex items-center gap-1 text-[10px] font-bold text-neutral-500 dark:text-neutral-600">
            <svg
              className="h-3 w-3"
              fill="none"
              viewBox="0 0 24 24"
              stroke="currentColor"
            >
              <path
                d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z"
                strokeWidth={2}
              />
            </svg>
            {deal.lastActivity}
          </div>
        </div>
      </div>
    </div>
  );
};

export default DealCard;

"use client";

import { type LucideIcon } from "lucide-react";
import {
  SidebarGroup,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
} from "./ui/sidebar";
import { useLocation } from "react-router-dom";

export function NavMain({
  items,
  onNavigate,
  currentView,
}: {
  items: {
    title: string;
    url: string;
    icon?: LucideIcon;
    isActive?: boolean;
    isDisabled?: boolean;
    items?: {
      title: string;
      url: string;
    }[];
  }[];
  onNavigate?: (view: string) => void;
  currentView?: string;
}) {
  const location = useLocation();
  const pathname = location.pathname;
  return (
    <SidebarGroup className="border-b border-neutral-200 dark:border-neutral-800">
      <SidebarMenu>
        {items.map((item) => (
          <SidebarMenuItem key={item.title}>
            <SidebarMenuButton
              asChild
              tooltip={item.title}
              isActive={currentView === item.title || (pathname === item.url && item.url !== "#")}
              className="data-[active=true]:border-y data-[active=true]:border-neutral-200 dark:data-[active=true]:border-neutral-600 text-neutral-500 dark:text-neutral-400 font-medium tracking-tight"
            >
              <a
                href={item.url}
                onClick={(e) => {
                  if (item.isDisabled) {
                    e.preventDefault();
                    return;
                  }
                  if (item.url === "#" && onNavigate) {
                    e.preventDefault();
                    onNavigate(item.title);
                  }
                }}
              >
                {item.icon && (
                  <item.icon className="size-4" strokeWidth={2.5} />
                )}
                <span>{item.title}</span>
              </a>
            </SidebarMenuButton>
          </SidebarMenuItem>
        ))}
      </SidebarMenu>
    </SidebarGroup>
  );
}

"use client";

import { Dot } from "lucide-react";

import {
  SidebarGroup,
  SidebarGroupLabel,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
} from "./ui/sidebar";
import { useLocation } from "react-router-dom";

export function NavPipelines({
  pipelines,
}: {
  pipelines: {
    name: string;
    url: string;
    color: string;
    isDisabled?: boolean;
  }[];
}) {
  const location = useLocation();
  const pathname = location.pathname;
  return (
    <SidebarGroup className="group-data-[collapsible=icon]:hidden">
      <SidebarGroupLabel className="h-0 pt-1 pb-3.5 text-neutral-500 dark:text-neutral-400 -ml-1.5">PIPELINE</SidebarGroupLabel>
      <SidebarMenu>
        {pipelines.map((item) => (
          <SidebarMenuItem key={item.name}>
            <SidebarMenuButton asChild isActive={pathname === item.url} className="data-[active=true]:border-y data-[active=true]:border-neutral-200 dark:data-[active=true]:border-neutral-700 text-neutral-500 dark:text-neutral-400 font-medium tracking-tight">
              <a href={item.url} onClick={(e) => item.isDisabled && e.preventDefault()}>
                <Dot className={`${item.color}`} strokeWidth={10} />
                <span >{item.name}</span>
              </a>
            </SidebarMenuButton>
          </SidebarMenuItem>
        ))}
      </SidebarMenu>
    </SidebarGroup>
  );
}

"use client";

import { type LucideIcon } from "lucide-react";

import {
  SidebarGroup,
  SidebarGroupLabel,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
} from "./ui/sidebar";
import { useLocation } from "react-router-dom";

export function NavReporting({
  reports,
}: {
  reports: {
    name: string;
    url: string;
    icon: LucideIcon;
    isDisabled?: boolean;
  }[];
}) {
  const location = useLocation();
  const pathname = location.pathname;
  return (
    <SidebarGroup className="group-data-[collapsible=icon]:hidden border-b border-neutral-200 dark:border-neutral-800">
      <SidebarGroupLabel className="h-0 pt-1 pb-3.5 text-neutral-500 dark:text-neutral-400 -ml-1.5">REPORTS</SidebarGroupLabel>
      <SidebarMenu>
        {reports.map((item) => (
          <SidebarMenuItem key={item.name}>
            <SidebarMenuButton asChild isActive={pathname === item.url} className="data-[active=true]:border-y data-[active=true]:border-neutral-200 dark:data-[active=true]:border-neutral-700 text-neutral-500 dark:text-neutral-400 font-medium tracking-tight">
              <a href={item.url} onClick={(e) => item.isDisabled && e.preventDefault()}>
                <item.icon className="size-4" strokeWidth={2.5} />
                <span >{item.name}</span>
              </a>
            </SidebarMenuButton>
          </SidebarMenuItem>
        ))}
      </SidebarMenu>
    </SidebarGroup>
  );
}

import * as React from "react"
import { type LucideIcon } from "lucide-react"
import {
  SidebarGroup,
  SidebarGroupContent,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
} from "./ui/sidebar"
export function NavSecondary({
  items,
  ...props
}: {
  items: {
    title: string
    url: string
    icon: LucideIcon
    isDisabled?: boolean
  }[]
} & React.ComponentPropsWithoutRef<typeof SidebarGroup>) {
  return (
    <SidebarGroup {...props} >
      <SidebarGroupContent>
        <SidebarMenu>
          {items.map((item) => (
            <SidebarMenuItem key={item.title}>
              <SidebarMenuButton asChild size="sm" className="text-neutral-500 font-medium tracking-tight">
                <a href={item.url} onClick={(e) => item.isDisabled && e.preventDefault()}>
                  <item.icon />
                  <span>{item.title}</span>
                </a>
              </SidebarMenuButton>
            </SidebarMenuItem>
          ))}
        </SidebarMenu>
      </SidebarGroupContent>
    </SidebarGroup>
  )
}

"use client";

import { type LucideIcon } from "lucide-react";

import {
  SidebarGroup,
  SidebarGroupLabel,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
} from "./ui/sidebar";
import { useLocation } from "react-router-dom";

export function NavTeams({
  teams,
}: {
  teams: {
    name: string;
    url: string;
    icon: LucideIcon;
    isDisabled?: boolean;
  }[];
}) {
  const location = useLocation();
  const pathname = location.pathname;
  return (
    <SidebarGroup className="group-data-[collapsible=icon]:hidden border-b border-neutral-200 dark:border-neutral-800">
      <SidebarGroupLabel className="h-0 pt-1 pb-3.5 text-neutral-500 dark:text-neutral-400 -ml-1.5">TEAM</SidebarGroupLabel>
      <SidebarMenu>
        {teams.map((item) => (
          <SidebarMenuItem key={item.name}>
            <SidebarMenuButton asChild isActive={pathname === item.url} className="data-[active=true]:border-y data-[active=true]:border-neutral-200 dark:data-[active=true]:border-neutral-700 text-neutral-500 dark:text-neutral-400 font-medium tracking-tight">
              <a href={item.url} onClick={(e) => item.isDisabled && e.preventDefault()}>
                <item.icon className="size-4" strokeWidth={2.5} />
                <span >{item.name}</span>
              </a>
            </SidebarMenuButton>
          </SidebarMenuItem>
        ))}
      </SidebarMenu>
    </SidebarGroup>
  );
}

'use client';
import { useState, useMemo } from 'react';
import { Breadcrumb, BreadcrumbItem, BreadcrumbLink } from './ui/breadcrumb';
import { Separator } from './ui/separator';
import { SidebarTrigger } from './ui/sidebar';
import { Badge } from './ui/badge';
import {
  Bell,
  Search,
  Building2,
  Kanban,
  Settings,
  CreditCard,
  LogOut,
  User,
  AlertTriangle,
  CheckCircle2,
} from 'lucide-react';
import { useLocation } from 'react-router-dom';
import { Dialog, DialogContent } from './ui/dialog';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from './ui/dropdown-menu';
import { Input } from './ui/input';
import { companiesData, deals } from '../data';

const NOTIFICATIONS = [
  {
    id: 1,
    Icon: CheckCircle2,
    title: 'Stripe deal marked as Closed Won',
    description: 'Noah Lee closed the deal · $442k',
    time: '5m ago',
    unread: true,
    iconColor: 'text-green-500',
    iconBg: 'bg-green-100 dark:bg-green-900/30',
  },
  {
    id: 2,
    Icon: Kanban,
    title: 'Apple deal moved to Negotiation',
    description: 'Alex Santos updated the stage',
    time: '1h ago',
    unread: true,
    iconColor: 'text-indigo-500',
    iconBg: 'bg-indigo-100 dark:bg-indigo-900/30',
  },
  {
    id: 3,
    Icon: Building2,
    title: 'LVMH QBR Call scheduled',
    description: 'Sarah Nguyen created an activity',
    time: '3h ago',
    unread: true,
    iconColor: 'text-blue-500',
    iconBg: 'bg-blue-100 dark:bg-blue-900/30',
  },
  {
    id: 4,
    Icon: AlertTriangle,
    title: 'Follow-up with Disney due today',
    description: 'Discovery call reminder',
    time: '6h ago',
    unread: false,
    iconColor: 'text-orange-500',
    iconBg: 'bg-orange-100 dark:bg-orange-900/30',
  },
  {
    id: 5,
    Icon: User,
    title: 'James Taylor mentioned you',
    description: 'In a comment on the Disney deal',
    time: 'Yesterday',
    unread: false,
    iconColor: 'text-neutral-500',
    iconBg: 'bg-neutral-100 dark:bg-neutral-800',
  },
];

export const SiteHeader = ({ currentView }: { currentView?: string }) => {
  const location = useLocation();
  const pathname = location.pathname;

  const [searchOpen, setSearchOpen] = useState(false);
  const [query, setQuery] = useState('');
  const [readIds, setReadIds] = useState<Set<number>>(new Set());

  const unreadCount = NOTIFICATIONS.filter(
    (n) => n.unread && !readIds.has(n.id),
  ).length;

  const markAllRead = () => setReadIds(new Set(NOTIFICATIONS.map((n) => n.id)));

  const markRead = (id: number) => setReadIds((prev) => new Set([...prev, id]));

  const getBreadcrumbLabel = () => {
    if (currentView) return currentView;
    if (pathname.includes('company')) return 'Companies';
    if (pathname.includes('dealsboard')) return 'Deals Board';
    return 'Dashboard';
  };

  const filteredCompanies = useMemo(() => {
    const q = query.trim().toLowerCase();
    if (!q) return [];
    return companiesData
      .filter((c) => c.name.toLowerCase().includes(q))
      .slice(0, 4);
  }, [query]);

  const filteredDeals = useMemo(() => {
    const q = query.trim().toLowerCase();
    if (!q) return [];
    return deals.filter((d) => d.company.toLowerCase().includes(q)).slice(0, 3);
  }, [query]);

  const hasResults = filteredCompanies.length > 0 || filteredDeals.length > 0;
  const showEmpty = query.trim().length > 0 && !hasResults;

  return (
    <header className="flex h-16 justify-between border-neutral-200 pr-5 dark:border-none">
      {/* Left — breadcrumb */}
      <div className="flex items-center gap-2 px-4">
        <SidebarTrigger className="-ml-1" />
        <Separator
          orientation="vertical"
          className="my-auto mr-2 data-[orientation=vertical]:h-4"
        />
        <div className="flex items-center gap-2">
          <Breadcrumb>
            <BreadcrumbItem className="flex items-center gap-1">
              <BreadcrumbLink href="#">{getBreadcrumbLabel()}</BreadcrumbLink>
            </BreadcrumbItem>
          </Breadcrumb>
          <Badge variant="secondary" className="text-xs">
            <div className="size-1.5 rounded-full bg-green-600" />
            Active
          </Badge>
        </div>
      </div>

      {/* Right — actions */}
      <div className="flex items-center gap-2">
        {/* ── Search ── */}
        <button
          onClick={() => setSearchOpen(true)}
          className="flex size-7 cursor-pointer items-center justify-center rounded-full border-y border-neutral-200 bg-neutral-100 text-neutral-900 transition-colors hover:bg-neutral-200/50 dark:border-neutral-600 dark:bg-neutral-800 dark:text-white dark:hover:bg-neutral-700/50"
        >
          <Search className="size-4" />
        </button>

        <Dialog
          open={searchOpen}
          onOpenChange={(open) => {
            setSearchOpen(open);
            if (!open) setQuery('');
          }}
        >
          <DialogContent
            showCloseButton={false}
            className="top-[14%] translate-y-0 gap-0 overflow-hidden p-0 sm:max-w-lg"
          >
            <span className="sr-only">Search</span>

            {/* Single flex container — prevents grid row-sizing from collapsing body to zero */}
            <div className="flex flex-col">
              {/* input row */}
              <div className="flex items-center gap-3 px-4">
                <Search className="size-4 shrink-0 text-neutral-400 dark:text-neutral-500" />
                <Input
                  autoFocus
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  placeholder="Search companies, deals…"
                  className="h-12 border-0 bg-transparent dark:bg-transparent rounded-none px-0 text-sm shadow-none ring-0 placeholder:text-neutral-400 focus-visible:ring-0 dark:placeholder:text-neutral-600"
                />
                <kbd className="hidden shrink-0 rounded border border-neutral-200 px-1.5 py-0.5 text-[10px] text-neutral-400 sm:inline dark:border-neutral-700 dark:text-neutral-600">
                  ESC
                </kbd>
              </div>

              {/* thin rule */}
              <div className="h-px bg-neutral-100 dark:bg-neutral-800" />

              {/* default state — recent companies */}
              {query.trim() === '' && (
                <div className="p-2 pb-3">
                  <p className="px-2 py-1.5 text-[10px] font-semibold tracking-wider text-neutral-400 uppercase dark:text-neutral-600">
                    Recent
                  </p>
                  {companiesData.slice(0, 4).map((company) => (
                    <div
                      key={company.id}
                      onClick={() => setSearchOpen(false)}
                      className="flex cursor-pointer items-center gap-3 rounded-lg px-2 py-2 hover:bg-neutral-100 dark:hover:bg-neutral-800"
                    >
                      <div className="flex size-7 shrink-0 items-center justify-center rounded-md border border-neutral-200 bg-neutral-50 dark:border-neutral-700 dark:bg-neutral-800/60">
                        <Building2 className="size-3.5 text-neutral-400 dark:text-neutral-500" />
                      </div>
                      <div className="min-w-0 flex-1">
                        <p className="text-sm font-medium text-neutral-900 dark:text-white">
                          {company.name}
                        </p>
                        <p className="text-xs text-neutral-400 dark:text-neutral-500">
                          {company.openDeals} open deals · $
                          {(company.pipelineValue / 1000).toFixed(0)}k pipeline
                        </p>
                      </div>
                      <span className="text-xs text-neutral-300 dark:text-neutral-700">
                        ↵
                      </span>
                    </div>
                  ))}
                </div>
              )}

              {/* no results */}
              {showEmpty && (
                <div className="px-4 py-8 text-center">
                  <p className="text-sm text-neutral-400 dark:text-neutral-500">
                    No results for{' '}
                    <span className="font-medium text-neutral-600 dark:text-neutral-400">
                      &ldquo;{query}&rdquo;
                    </span>
                  </p>
                </div>
              )}

              {/* results */}
              {hasResults && (
                <div className="max-h-72 overflow-y-auto p-2 pb-3">
                  {filteredCompanies.length > 0 && (
                    <>
                      <p className="px-2 py-1.5 text-[10px] font-semibold tracking-wider text-neutral-400 uppercase dark:text-neutral-600">
                        Companies
                      </p>
                      {filteredCompanies.map((company) => (
                        <div
                          key={company.id}
                          onClick={() => setSearchOpen(false)}
                          className="flex cursor-pointer items-center gap-3 rounded-lg px-2 py-2 hover:bg-neutral-100 dark:hover:bg-neutral-800"
                        >
                          <div className="flex size-7 shrink-0 items-center justify-center rounded-md border border-neutral-200 bg-neutral-50 dark:border-neutral-700 dark:bg-neutral-800/60">
                            <Building2 className="size-3.5 text-neutral-500" />
                          </div>
                          <div className="min-w-0">
                            <p className="text-sm font-medium text-neutral-900 dark:text-white">
                              {company.name}
                            </p>
                            <p className="text-xs text-neutral-400 dark:text-neutral-500">
                              {company.openDeals} open deals · $
                              {(company.pipelineValue / 1000).toFixed(0)}k
                              pipeline
                            </p>
                          </div>
                        </div>
                      ))}
                    </>
                  )}

                  {filteredDeals.length > 0 && (
                    <>
                      {filteredCompanies.length > 0 && (
                        <div className="my-1 h-px bg-neutral-100 dark:bg-neutral-800" />
                      )}
                      <p className="px-2 py-1.5 text-[10px] font-semibold tracking-wider text-neutral-400 uppercase dark:text-neutral-600">
                        Deals
                      </p>
                      {filteredDeals.map((deal) => (
                        <div
                          key={deal.id}
                          onClick={() => setSearchOpen(false)}
                          className="flex cursor-pointer items-center gap-3 rounded-lg px-2 py-2 hover:bg-neutral-100 dark:hover:bg-neutral-800"
                        >
                          <div className="flex size-7 shrink-0 items-center justify-center rounded-md border border-indigo-100 bg-indigo-50 dark:border-indigo-800 dark:bg-indigo-900/20">
                            <Kanban className="size-3.5 text-indigo-500" />
                          </div>
                          <div className="min-w-0">
                            <p className="text-sm font-medium text-neutral-900 dark:text-white">
                              {deal.company}
                            </p>
                            <p className="text-xs text-neutral-400 dark:text-neutral-500">
                              {deal.stage} · ${deal.value.toLocaleString()}
                            </p>
                          </div>
                        </div>
                      ))}
                    </>
                  )}
                </div>
              )}
            </div>
          </DialogContent>
        </Dialog>

        {/* ── Notifications ── */}
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <button className="relative flex size-7 cursor-pointer items-center justify-center rounded-full border-y border-neutral-200 bg-neutral-100 text-neutral-900 transition-colors hover:bg-neutral-200/50 dark:border-neutral-600 dark:bg-neutral-800 dark:text-white dark:hover:bg-neutral-700/50">
              <Bell className="size-4" />
              {unreadCount > 0 && (
                <span className="absolute -top-0.5 -right-0.5 flex size-3.5 items-center justify-center rounded-full bg-indigo-600 text-[8px] leading-none font-bold text-white">
                  {unreadCount}
                </span>
              )}
            </button>
          </DropdownMenuTrigger>

          <DropdownMenuContent
            align="end"
            className="w-80 overflow-hidden border-neutral-200 bg-white p-0 dark:border-neutral-800 dark:bg-neutral-900"
          >
            {/* header */}
            <div className="flex items-center justify-between border-b border-neutral-100 px-4 py-3 dark:border-neutral-800">
              <div className="flex items-center gap-2">
                <span className="text-sm font-semibold text-neutral-900 dark:text-white">
                  Notifications
                </span>
                {unreadCount > 0 && (
                  <span className="flex h-4 min-w-4 items-center justify-center rounded-full bg-indigo-600 px-1 text-[10px] font-bold text-white">
                    {unreadCount}
                  </span>
                )}
              </div>
              {unreadCount > 0 && (
                <button
                  onClick={markAllRead}
                  className="cursor-pointer text-xs text-indigo-600 hover:underline dark:text-indigo-400"
                >
                  Mark all read
                </button>
              )}
            </div>

            {/* items */}
            <div className="divide-y divide-neutral-100 dark:divide-neutral-800">
              {NOTIFICATIONS.map((n) => {
                const isUnread = n.unread && !readIds.has(n.id);
                return (
                  <div
                    key={n.id}
                    onClick={() => markRead(n.id)}
                    className={`flex cursor-pointer gap-3 px-4 py-3 hover:bg-neutral-50 dark:hover:bg-neutral-800/50 ${isUnread ? 'bg-indigo-50/50 dark:bg-indigo-950/20' : ''}`}
                  >
                    <div
                      className={`flex size-7 shrink-0 items-center justify-center rounded-full ${n.iconBg}`}
                    >
                      <n.Icon className={`size-3.5 ${n.iconColor}`} />
                    </div>
                    <div className="min-w-0 flex-1">
                      <p
                        className={`text-[13px] leading-snug ${isUnread ? 'font-medium text-neutral-900 dark:text-white' : 'text-neutral-500 dark:text-neutral-400'}`}
                      >
                        {n.title}
                      </p>
                      <p className="mt-0.5 text-xs text-neutral-400 dark:text-neutral-500">
                        {n.description}
                      </p>
                      <p className="mt-0.5 text-[11px] text-neutral-400 dark:text-neutral-600">
                        {n.time}
                      </p>
                    </div>
                    {isUnread && (
                      <div className="mt-1.5 size-1.5 shrink-0 rounded-full bg-indigo-500" />
                    )}
                  </div>
                );
              })}
            </div>
          </DropdownMenuContent>
        </DropdownMenu>

        {/* ── User ── */}
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <div className="flex h-fit cursor-pointer items-center justify-center gap-2 rounded-full border-y border-neutral-200 bg-neutral-100 p-1 text-neutral-900 transition-colors hover:bg-neutral-200/50 md:pr-2.5 dark:border-neutral-600 dark:bg-neutral-800 dark:text-white dark:hover:bg-neutral-700/50">
              <img
                src="https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?q=80&w=1480&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D"
                alt="user"
                height={20}
                width={20}
                className="size-5 rounded-full object-cover"
              />
              <span className="hidden text-xs sm:inline">John doe</span>
            </div>
          </DropdownMenuTrigger>

          <DropdownMenuContent
            align="end"
            className="w-56 border-neutral-200 bg-white dark:border-neutral-800 dark:bg-neutral-900"
          >
            {/* profile */}
            <div className="flex items-center gap-3 px-3 py-2.5">
              <img
                src="https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?q=80&w=1480&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D"
                alt="user"
                className="size-8 rounded-full object-cover"
              />
              <div className="min-w-0">
                <p className="truncate text-sm font-medium text-neutral-900 dark:text-white">
                  John Doe
                </p>
                <p className="truncate text-xs text-neutral-500 dark:text-neutral-400">
                  john@example.com
                </p>
              </div>
            </div>

            <DropdownMenuSeparator />

            <DropdownMenuLabel className="text-[10px] font-semibold tracking-wider text-neutral-400 uppercase dark:text-neutral-600">
              Account
            </DropdownMenuLabel>

            <DropdownMenuItem className="cursor-pointer gap-2.5">
              <User className="size-4 text-neutral-500" />
              View Profile
            </DropdownMenuItem>
            <DropdownMenuItem className="cursor-pointer gap-2.5">
              <Settings className="size-4 text-neutral-500" />
              Settings
            </DropdownMenuItem>
            <DropdownMenuItem className="cursor-pointer gap-2.5">
              <CreditCard className="size-4 text-neutral-500" />
              Billing
            </DropdownMenuItem>

            <DropdownMenuSeparator />

            <DropdownMenuItem
              variant="destructive"
              className="cursor-pointer gap-2.5"
            >
              <LogOut className="size-4" />
              Log out
            </DropdownMenuItem>
          </DropdownMenuContent>
        </DropdownMenu>
      </div>
    </header>
  );
};

